import { Component, OnInit } from "@angular/core";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { UsersService } from 'src/app/shared/services/user.service';
import { SecurityDto } from "../auth/login/login.component";

import Swal from "sweetalert2";
import { ApiService } from "src/app/shared/services/api.service";
import { Router } from "@angular/router";
import * as CryptoJS from "crypto-js";
import { SecurityPolicyService } from "src/app/shared/services/security-policy.service";
import {
  ChangePasswordDTO,
  ChangePasswordRespDTO,
} from "../change-password/change-password-dto";


@Component({
  selector: "npr-profile",
  templateUrl: "./profile.component.html",
  styleUrls: ["./profile.component.scss"],
})
export class ProfileComponent implements OnInit {
  loggedInUser: any;
  var1: any;
  hide1 = true;
  hide = true;
  hide2 = true;
  userForm: FormGroup;
  submit: boolean = false;
  user: string;
  url: any;
  profileId: any;
  profilePicture: any;
  constructor(
    private api: ApiService,
    private fb: FormBuilder,
    private router: Router,
    private apiService: SecurityPolicyService,
    private userApi: UsersService,
  ) {}

  ngOnInit() {
    this.loggedInUser = localStorage.getItem("userFromLogin");
    this.user = localStorage.getItem("userobj");
    console.log(JSON.parse(this.user))
    this.userForm = new FormGroup({
      userId: new FormControl("", Validators.required),
      userName: new FormControl("", Validators.required),
      department: new FormControl("", [Validators.required]),
    });
    this.getProfileImage(JSON.parse(this.user).userId);
    this.buildForm(JSON.parse(this.user));
   
  }
  buildForm(item) {

      this.userForm = new FormGroup({
        userId: new FormControl(item?item.userId:"", Validators.required),
        userName: new FormControl(item?item.userName:"", Validators.required),
        department: new FormControl(item?item.department:"", [Validators.required]),
    });
  }
  getProfileImage(userId) {
    
    this.userApi.getCustomerDocuments(userId).subscribe((data) => {
      console.log('data ::', data);
      if (data) {
        this.profileId = data.id;
        
        this.url = data.fileUrl;
      }
    });
  }
  onSelectFile(event) {
    console.log(event, 'Event');
    if (event.target.files && event.target.files[0]) {
      this.profilePicture = event.target.files[0];
      var reader = new FileReader();

      reader.readAsDataURL(event.target.files[0]); // read file as data url

      reader.onload = (event) => {
        // called once readAsDataURL is completed
        console.log('Profile Image Test:: ', reader.result);
        this.url = event.target.result;
        console.log(this.url, 'URL');
      };
    }
  }
  submitPhoto(){
    if (this.profilePicture) {
      console.log(this.profilePicture);
      let profileUpload: any = {};
      profileUpload.fileType = this.profilePicture.type;
      profileUpload.fileName = this.profilePicture.name;
      profileUpload.userId = JSON.parse(this.user).userId;
      console.log(profileUpload);
      const uploadData = new FormData();
      uploadData.append('data', JSON.stringify(profileUpload));
      uploadData.append('file', this.profilePicture);
      this.userApi.uploadDocument(uploadData).subscribe((response) => {
        console.log(response);
        if(response.statusCodeValue === 200){
          Swal.fire({text:"Image Uploaded Successfully",
        icon:"success"})
        }
      });
    }
  }
  public delete() {
    Swal.fire({
      text: 'You are trying to delete image. ' + ' Do you want to proceed?',
      showCancelButton: true,
      confirmButtonColor: '#E6224A',
      cancelButtonColor: '#011945',
      // confirmButtonText: 'PROCEED.'
      cancelButtonText: 'NO',
      confirmButtonText: 'YES',
      icon: 'info',
    }).then((result) => {
      if (result.isConfirmed === true) {
        this.url = null;
        this.userApi.deleteProfileImage(JSON.parse(this.user).userId).subscribe(resp=>{
          console.log("resp after deletion ",resp)
          if(resp=== true){
            Swal.fire({text:"Image deleted Successfully",
            icon:"success"})
          }
        })
      }
    });
  }

}

